SELECT * FROM knowledge_document


        AND (title LIKE CONCAT('%', #{keyword}, '%')
             OR content LIKE CONCAT('%', #{keyword}, '%')
             OR summary LIKE CONCAT('%', #{keyword}, '%'))


        AND category = #{category}


        AND status = #{status}


        AND author = #{author}




